<?php include 'header.php'; $cat=$_GET['category']??''; $search=$_GET['search']??''; $sql='SELECT * FROM products WHERE 1'; $params=[]; if($cat){$sql.=' AND category=?'; $params[]=$cat;} if($search){$sql.=' AND (name LIKE ? OR brand LIKE ?)'; $params[]="%$search%"; $params[]="%$search%";} $stmt=$pdo->prepare($sql); $stmt->execute($params); ?>
<section class="section"><h1>Shop</h1><form class="filters" method="GET"><input name="search" placeholder="Search bikes or parts..." value="<?= htmlspecialchars($search); ?>"><select name="category"><option value="">All categories</option><option value="motorcycle" <?= $cat==='motorcycle'?'selected':''; ?>>Motorcycles</option><option value="spare_part" <?= $cat==='spare_part'?'selected':''; ?>>Spare Parts</option></select><button class="btn">Filter</button></form><div class="grid"><?php foreach($stmt as $p): ?><div class="card"><img src="<?= htmlspecialchars($p['image']); ?>"><h3><?= htmlspecialchars($p['name']); ?></h3><p><?= htmlspecialchars($p['brand']); ?> • Stock: <?= $p['stock']; ?></p><strong>$<?= number_format($p['price'],2); ?></strong><a class="btn small" href="product.php?id=<?= $p['id']; ?>">View Product</a></div><?php endforeach; ?></div></section><?php include 'footer.php'; ?>
